// Hashi (Bridges) game logic utilities

export function canonicalBridgeKey(a, b) {
  // key is based on grid coordinates (x,y) not ids
  const p1 = { x: a.x, y: a.y };
  const p2 = { x: b.x, y: b.y };

  let first = p1;
  let second = p2;
  if (p2.x < p1.x || (p2.x === p1.x && p2.y < p1.y)) {
    first = p2;
    second = p1;
  }
  return `${first.x},${first.y},${second.x},${second.y}`;
}

export function parseBridgeKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
  return { x1, y1, x2, y2 };
}

export function isAxisAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

export function areAdjacent(islands, a, b) {
  if (!isAxisAligned(a, b)) return false;

  if (a.x === b.x) {
    const x = a.x;
    const yMin = Math.min(a.y, b.y);
    const yMax = Math.max(a.y, b.y);
    // adjacent if no island strictly between them on the same column
    return !islands.some((i) => i.id !== a.id && i.id !== b.id && i.x === x && i.y > yMin && i.y < yMax);
  }

  const y = a.y;
  const xMin = Math.min(a.x, b.x);
  const xMax = Math.max(a.x, b.x);
  return !islands.some((i) => i.id !== a.id && i.id !== b.id && i.y === y && i.x > xMin && i.x < xMax);
}

function rangesOverlap(a1, a2, b1, b2) {
  const minA = Math.min(a1, a2);
  const maxA = Math.max(a1, a2);
  const minB = Math.min(b1, b2);
  const maxB = Math.max(b1, b2);
  return Math.max(minA, minB) < Math.min(maxA, maxB);
}

export function bridgesWouldCross(islands, bridges, a, b) {
  if (!isAxisAligned(a, b)) return false;

  const newIsVertical = a.x === b.x;
  const newX1 = a.x;
  const newY1 = a.y;
  const newX2 = b.x;
  const newY2 = b.y;

  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const existingVertical = x1 === x2;

    // Same orientation can overlap/duplicate but not "cross" in Hashi terms.
    if (existingVertical === newIsVertical) continue;

    // Check proper intersection (not at endpoints).
    // vertical segment at x = xv, y in (yvMin, yvMax)
    // horizontal segment at y = yh, x in (xhMin, xhMax)
    let xv, yv1, yv2, yh, xh1, xh2;
    if (existingVertical) {
      xv = x1;
      yv1 = y1;
      yv2 = y2;
      yh = newY1;
      xh1 = newX1;
      xh2 = newX2;
    } else {
      xv = newX1;
      yv1 = newY1;
      yv2 = newY2;
      yh = y1;
      xh1 = x1;
      xh2 = x2;
    }

    // intersection at (xv, yh)
    const vMin = Math.min(yv1, yv2);
    const vMax = Math.max(yv1, yv2);
    const hMin = Math.min(xh1, xh2);
    const hMax = Math.max(xh1, xh2);

    const intersects = xv > hMin && xv < hMax && yh > vMin && yh < vMax;
    if (!intersects) continue;

    // If intersection point is an island coordinate, allow (it means meeting at island).
    const intersectionIsIsland = islands.some((i) => i.x === xv && i.y === yh);
    if (!intersectionIsIsland) return true;
  }

  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + count);
    counts.set(b.id, (counts.get(b.id) ?? 0) + count);
  }
  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to) return { valid: false, error: 'Invalid islands' };
  if (from.id === to.id) return { valid: false, error: 'Cannot connect island to itself' };
  if (!isAxisAligned(from, to) || !areAdjacent(islands, from, to)) {
    return { valid: false, error: 'Cannot connect non-adjacent islands' };
  }

  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;

  if (next > 2) return { valid: false, error: 'Max 2 bridges per pair' };
  if (next < 0) return { valid: false, error: 'Invalid bridge count' };

  // Crossing check is for adding (delta > 0) only
  if (delta > 0) {
    const temp = new Map(bridges);
    temp.set(key, next);
    if (bridgesWouldCross(islands, temp, from, to)) {
      return { valid: false, error: 'Bridges would cross' };
    }
  }

  // Island capacity check
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) ?? 0;
  const toCount = counts.get(to.id) ?? 0;

  if (delta > 0) {
    if (fromCount + delta > from.value || toCount + delta > to.value) {
      return { valid: false, error: 'Island would exceed its number' };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const stack = [start];
  while (stack.length) {
    const cur = stack.pop();
    for (const n of adj.get(cur) || []) {
      if (!seen.has(n)) {
        seen.add(n);
        stack.push(n);
      }
    }
  }

  return islands.every((i) => seen.has(i.id));
}

export function isVictory(islands, bridges) {
  // counts satisfied
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  // no crossings
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    if (bridgesWouldCross(islands, bridges, a, b)) return false;
  }

  // connected
  return checkConnectivity(islands, bridges);
}
