import React, { useEffect, useMemo, useState } from 'react';
import { PUZZLES, PUZZLE_OPTIONS } from './data/puzzles';
import {
  areAdjacent,
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory,
  parseBridgeKey
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function findIslandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

function islandsInDirection(islands, from, dir) {
  // Return nearest island strictly in direction if exists.
  // dir: 'left'|'right'|'up'|'down'
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

function bridgeLinesForKey(key, count) {
  // returns [{x1,y1,x2,y2, offset:{dx,dy}, index}]
  const { x1, y1, x2, y2 } = parseBridgeKey(key);
  const vertical = x1 === x2;

  if (count === 1) {
    return [{ x1, y1, x2, y2, dx: 0, dy: 0, idx: 0 }];
  }

  if (count === 2) {
    // offset by 4px perpendicular in pixel space => 4/GRID in grid units
    const off = 4 / GRID;
    if (vertical) {
      return [
        { x1: x1 - off, y1, x2: x2 - off, y2, dx: -off, dy: 0, idx: 0 },
        { x1: x1 + off, y1, x2: x2 + off, y2, dx: off, dy: 0, idx: 1 }
      ];
    }
    return [
      { x1, y1: y1 - off, x2, y2: y2 - off, dx: 0, dy: -off, idx: 0 },
      { x1, y1: y1 + off, x2, y2: y2 + off, dx: 0, dy: off, idx: 1 }
    ];
  }

  return [];
}

export default function App() {
  const [puzzleKey, setPuzzleKey] = useState('Easy');
  const islands = useMemo(() => PUZZLES[puzzleKey].islands, [puzzleKey]);

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // first click/enter selection
  const [cursorId, setCursorId] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);

  // Park cursor on id=0 after any puzzle change (and reset everything)
  useEffect(() => {
    setCursorId(0);
    setSelectedId(null);
    setError(null);
    setVictory(false);
    setBridges(new Map());
  }, [puzzleKey]);

  // Keep cursor parked on id=0 after any puzzle change AND after any puzzle change was already handled.
  // (Requirement: after any puzzle change; also after any puzzle change selection etc.)

  useEffect(() => {
    setVictory(isVictory(islands, bridges));
  }, [islands, bridges]);

  function clearAfterValidMove() {
    setError(null);
  }

  function resetAll() {
    setBridges(new Map());
    setSelectedId(null);
    setCursorId(0);
    setError(null);
    setVictory(false);
  }

  function applyToggle(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    const next = current === 0 ? 1 : current === 1 ? 2 : 0;

    // Validate as delta steps if adding. For removal (next=0) always allowed.
    if (next === 0) {
      const nb = new Map(bridges);
      nb.delete(key);
      setBridges(nb);
      clearAfterValidMove();
      setSelectedId(null);
      setCursorId(0);
      return;
    }

    const delta = next - current;
    const check = canAddBridge(islands, bridges, from, to, delta);
    if (!check.valid) {
      // When second click produces an error, also reset the in-progress selection now.
      setError(check.error || 'Invalid move');
      setSelectedId(null);
      return;
    }

    const nb = new Map(bridges);
    nb.set(key, next);
    setBridges(nb);
    clearAfterValidMove();
    setSelectedId(null);
    setCursorId(0);
  }

  function onIslandActivate(id) {
    const island = islandById(islands, id);
    if (!island) return;

    // first click selects only
    if (selectedId == null) {
      setSelectedId(id);
      setError(null);
      return;
    }

    // second click against different island performs toggle
    if (selectedId === id) {
      // treat as reselect (no toggle)
      setSelectedId(id);
      setError(null);
      return;
    }

    const from = islandById(islands, selectedId);
    const to = island;
    if (!from || !to) {
      setSelectedId(null);
      return;
    }

    applyToggle(from, to);
  }

  function removeBridgeByKey(key) {
    if (!(bridges.get(key) > 0)) return;
    const nb = new Map(bridges);
    nb.delete(key);
    setBridges(nb);
    setError(null);
    setSelectedId(null);
    setCursorId(0);
  }

  function onBridgeLineContextMenu(e, key) {
    e.preventDefault();
    removeBridgeByKey(key);
  }

  function onBridgeLineClick(e, key) {
    if (e.ctrlKey) {
      removeBridgeByKey(key);
    }
  }

  // keyboard controls on window/document (not focused element)
  useEffect(() => {
    function onKeyDown(e) {
      if (e.key === 'Escape') {
        setSelectedId(null);
        setError(null);
        return;
      }

      const cur = islandById(islands, cursorId) || islands[0];
      if (!cur) return;

      const move = (dir) => {
        const target = islandsInDirection(islands, cur, dir);
        if (target) setCursorId(target.id);
      };

      if (e.key === 'ArrowLeft') move('left');
      else if (e.key === 'ArrowRight') move('right');
      else if (e.key === 'ArrowUp') move('up');
      else if (e.key === 'ArrowDown') move('down');
      else if (e.key === 'Enter') {
        // Enter selects or toggles, analogous to click
        const id = cursorId;
        if (selectedId == null) {
          setSelectedId(id);
          setError(null);
          return;
        }
        if (selectedId === id) {
          setSelectedId(id);
          setError(null);
          return;
        }

        const from = islandById(islands, selectedId);
        const to = islandById(islands, id);
        if (!from || !to) {
          setSelectedId(null);
          return;
        }

        // For keyboard we also want the descriptive "non-adjacent" error for non-adjacent
        if (!areAdjacent(islands, from, to)) {
          setError('Cannot connect non-adjacent islands');
          setSelectedId(null);
          return;
        }

        applyToggle(from, to);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [islands, cursorId, selectedId, bridges]);

  const bridgeRenderList = useMemo(() => {
    const items = [];
    for (const [key, count] of bridges.entries()) {
      if (!count) continue;
      const lines = bridgeLinesForKey(key, count);
      for (const ln of lines) items.push({ key, count, ...ln });
    }
    return items;
  }, [bridges]);

  const cursorIsland = islandById(islands, cursorId) || islands[0];

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleKey}
            onChange={(e) => {
              // Fully reset bridges/selection/error/victory in same update as swapping puzzle
              setPuzzleKey(e.target.value);
            }}
          >
            {PUZZLE_OPTIONS.map((k) => (
              <option key={k} value={k}>
                {k}
              </option>
            ))}
          </select>
        </label>
        <button onClick={resetAll}>Reset</button>
        {victory ? <div className="victory-banner">SOLVED!</div> : null}
        {error ? <div className="error-message">{error}</div> : null}
      </div>

      <svg className="board" width={SVG_W} height={SVG_H} viewBox={`0 0 ${SVG_W} ${SVG_H}`}>
        {/* Bridges */}
        {bridgeRenderList.map((b) => (
          <line
            key={`${b.key}:${b.idx}`}
            x1={b.x1 * GRID}
            y1={b.y1 * GRID}
            x2={b.x2 * GRID}
            y2={b.y2 * GRID}
            className="bridge"
            onContextMenu={(e) => onBridgeLineContextMenu(e, b.key)}
            onClick={(e) => onBridgeLineClick(e, b.key)}
          />
        ))}

        {/* Cursor (not a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorIsland.x * GRID - 18}
            y={cursorIsland.y * GRID - 18}
            width={36}
            height={36}
            className={selectedId === cursorIsland.id ? 'cursor cursor-selected' : 'cursor'}
          />
        ) : null}

        {/* Islands */}
        {islands.map((isl) => {
          const px = isl.x * GRID;
          const py = isl.y * GRID;
          const isSelected = selectedId === isl.id;
          const curCount = counts.get(isl.id) ?? 0;
          return (
            <g key={isl.id} onClick={() => onIslandActivate(isl.id)} className="island-group">
              <circle cx={px} cy={py} r={16} className={isSelected ? 'island island-selected' : 'island'} />
              <text x={px} y={py + 5} textAnchor="middle" className="island-text">
                {isl.value}
              </text>
              <text x={px} y={py + 28} textAnchor="middle" className="island-subtext">
                {curCount}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
