  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    if (bridgesWouldCross(islands, bridges, a, b)) return false;
